log("")
log("=" * 60)
log("PHASE 6: BP_EXOGameMode Configuration")
log("=" * 60)

try:
    gm_asset = unreal.load_asset(PATH_BP_GAMEMODE)
    if gm_asset is None:
        record("PHASE_6_STEP_01", False, "Could not load BP_EXOGameMode")
    else:
        record("PHASE_6_STEP_01", True, "Loaded BP_EXOGameMode")

        # Get the CDO (Class Default Object) from the Blueprint
        gm_class = unreal.load_class(None, PATH_BP_GAMEMODE + ".BP_EXOGameMode_C")
        if gm_class:
            cdo = unreal.get_default_object(gm_class)
        else:
            cdo = None

        # PHASE_6_STEP_02: Set DefaultPawnClass
        try:
            bp_char_class = unreal.load_class(None, PATH_BP_CHARACTER + ".BP_SWCharacter_C")
            if bp_char_class and cdo:
                cdo.set_editor_property("DefaultPawnClass", bp_char_class)
                record("PHASE_6_STEP_02", True, "DefaultPawnClass -> BP_SWCharacter")
            elif bp_char_class:
                # Try on the asset directly
                gm_asset.set_editor_property("DefaultPawnClass", bp_char_class)
                record("PHASE_6_STEP_02", True, "DefaultPawnClass -> BP_SWCharacter (via asset)")
            else:
                record("PHASE_6_STEP_02", False, "Could not load BP_SWCharacter class")
        except Exception as e:
            record("PHASE_6_STEP_02", False, "DefaultPawnClass: " + str(e))

        # PHASE_6_STEP_03: Set AvailableBiomes
        try:
            biome_names = ["DA_Biome_Forest", "DA_Biome_Desert", "DA_Biome_Mountain", "DA_Biome_Snow"]
            biomes = []
            for bn in biome_names:
                b = unreal.load_asset(PATH_BIOMES + "/" + bn)
                if b:
                    biomes.append(b)

            target = cdo if cdo else gm_asset
            if len(biomes) == 4:
                target.set_editor_property("AvailableBiomes", biomes)
                record("PHASE_6_STEP_03", True, "AvailableBiomes set (4 biomes)")
            else:
                record("PHASE_6_STEP_03", False, "Only loaded " + str(len(biomes)) + "/4 biomes")
        except Exception as e:
            record("PHASE_6_STEP_03", False, "AvailableBiomes: " + str(e))

        # PHASE_6_STEP_04: Set DefaultBiome
        try:
            forest = unreal.load_asset(PATH_BIOMES + "/DA_Biome_Forest")
            target = cdo if cdo else gm_asset
            if forest:
                target.set_editor_property("DefaultBiome", forest)
                record("PHASE_6_STEP_04", True, "DefaultBiome -> DA_Biome_Forest")
            else:
                record("PHASE_6_STEP_04", False, "Could not load DA_Biome_Forest")
        except Exception as e:
            record("PHASE_6_STEP_04", False, "DefaultBiome: " + str(e))

        # PHASE_6_STEP_05: Set TileRadius
        try:
            target = cdo if cdo else gm_asset
            target.set_editor_property("TileRadius", 1)
            record("PHASE_6_STEP_05", True, "TileRadius -> 1 (GTX 1070 target)")
        except Exception as e:
            record("PHASE_6_STEP_05", False, "TileRadius: " + str(e))

        # PHASE_6_STEP_06: Set POISpawnChance
        try:
            target = cdo if cdo else gm_asset
            target.set_editor_property("POISpawnChance", 0.15)
            record("PHASE_6_STEP_06", True, "POISpawnChance -> 0.15")
        except Exception as e:
            record("PHASE_6_STEP_06", False, "POISpawnChance: " + str(e))

        # Save the GameMode blueprint
        EAL.save_asset(PATH_BP_GAMEMODE)
        record("PHASE_6_STEP_07", True, "BP_EXOGameMode saved")

except Exception as e:
    record("PHASE_6_STEP_01", False, "BP_EXOGameMode load failed: " + str(e))

log("")
log("=" * 60)
log("PHASE 7: BP_SWCharacter Verification")
log("=" * 60)

try:
    char_asset = unreal.load_asset(PATH_BP_CHARACTER)
    if char_asset is None:
        record("PHASE_7_STEP_01", False, "Could not load BP_SWCharacter")
    else:
        record("PHASE_7_STEP_01", True, "Loaded BP_SWCharacter")

        char_class = unreal.load_class(None, PATH_BP_CHARACTER + ".BP_SWCharacter_C")
        char_cdo = unreal.get_default_object(char_class) if char_class else None
        target = char_cdo if char_cdo else char_asset

        # PHASE_7_STEP_02: Check skeletal mesh
        try:
            mesh_comp = target.get_editor_property("Mesh")
            if mesh_comp:
                sk_mesh = mesh_comp.get_editor_property("SkeletalMeshAsset") if hasattr(mesh_comp, "get_editor_property") else None
                if sk_mesh:
                    record("PHASE_7_STEP_02", True, "Skeletal mesh assigned: " + str(sk_mesh.get_name()))
                else:
                    record("PHASE_7_STEP_02", False, "Skeletal mesh component exists but no mesh assigned. Assign SK_SciFITrooper_Man_03 in editor.")
            else:
                record("PHASE_7_STEP_02", False, "No Mesh component found on BP_SWCharacter")
        except Exception as e:
            record("PHASE_7_STEP_02", False, "Mesh check: " + str(e))

        # PHASE_7_STEP_03: Check AnimBP class
        try:
            mesh_comp = target.get_editor_property("Mesh")
            if mesh_comp:
                anim_class = mesh_comp.get_editor_property("AnimClass") if hasattr(mesh_comp, "get_editor_property") else None
                if anim_class:
                    record("PHASE_7_STEP_03", True, "AnimClass set: " + str(anim_class.get_name()))
                else:
                    log_warn("AnimClass not set — attempting to assign ABP_SW_Combat")
                    abp = unreal.load_asset(PATH_ABP_COMBAT)
                    if abp:
                        abp_class_path = PATH_ABP_COMBAT + ".ABP_SW_Combat_C"
                        abp_class = unreal.load_class(None, abp_class_path)
                        if abp_class:
                            mesh_comp.set_editor_property("AnimClass", abp_class)
                            record("PHASE_7_STEP_03", True, "AnimClass assigned: ABP_SW_Combat")
                        else:
                            record("PHASE_7_STEP_03", False, "Could not load ABP_SW_Combat class. Set AnimClass manually in editor.")
                    else:
                        record("PHASE_7_STEP_03", False, "ABP_SW_Combat asset not found")
        except Exception as e:
            record("PHASE_7_STEP_03", False, "AnimClass check: " + str(e))

        # PHASE_7_STEP_04: Verify input actions
        try:
            missing_ia = []
            assigned_ia = []
            for prop_name, ia_path in IA_PATHS.items():
                if not EAL.does_asset_exist(ia_path):
                    missing_ia.append(prop_name + " (" + ia_path + ")")
                    continue
                try:
                    current = target.get_editor_property(prop_name)
                    if current is None:
                        ia_asset = unreal.load_asset(ia_path)
                        if ia_asset:
                            target.set_editor_property(prop_name, ia_asset)
                            assigned_ia.append(prop_name)
                    else:
                        assigned_ia.append(prop_name + " (already set)")
                except Exception:
                    # Property might not be directly accessible on CDO for some BP types
                    assigned_ia.append(prop_name + " (skipped — manual check)")

            if missing_ia:
                record("PHASE_7_STEP_04", False, "Missing IA assets: " + ", ".join(missing_ia))
            else:
                record("PHASE_7_STEP_04", True, str(len(assigned_ia)) + " input actions verified/assigned")
        except Exception as e:
            record("PHASE_7_STEP_04", False, "Input actions: " + str(e))

        # PHASE_7_STEP_05: Check DefaultMappingContext
        try:
            current_imc = target.get_editor_property("DefaultMappingContext")
            if current_imc is None:
                imc = unreal.load_asset(PATH_IMC_DEFAULT)
                if imc:
                    target.set_editor_property("DefaultMappingContext", imc)
                    record("PHASE_7_STEP_05", True, "DefaultMappingContext -> IMC_Default")
                else:
                    record("PHASE_7_STEP_05", False, "IMC_Default not found")
            else:
                record("PHASE_7_STEP_05", True, "DefaultMappingContext already set: " + str(current_imc.get_name()))
        except Exception as e:
            record("PHASE_7_STEP_05", False, "DefaultMappingContext: " + str(e))

        # Save character blueprint
        EAL.save_asset(PATH_BP_CHARACTER)
        record("PHASE_7_STEP_06", True, "BP_SWCharacter saved")

except Exception as e:
    record("PHASE_7_STEP_01", False, "BP_SWCharacter load failed: " + str(e))
